-- ═══════════════════════════════════════════════════════════════════════════
-- Phase-1 auth fix — confirm seeded auth users and ensure their profiles exist.
-- ═══════════════════════════════════════════════════════════════════════════
update auth.users
   set email_confirmed_at = coalesce(email_confirmed_at, now())
 where email in ('superadmin@chipafarm.com','internal@chipafarm.com','partner@chipafarm.com');

insert into public.users (id, email, full_name, role, is_active)
select u.id,
       u.email,
       case u.email
         when 'superadmin@chipafarm.com' then 'Chipa Owner'
         when 'internal@chipafarm.com'   then 'Internal Staff'
         else 'Finance Partner'
       end,
       (case u.email
         when 'superadmin@chipafarm.com' then 'super_admin'
         when 'internal@chipafarm.com'   then 'internal'
         else 'partner'
       end)::public.user_role,
       true
  from auth.users u
 where u.email in ('superadmin@chipafarm.com','internal@chipafarm.com','partner@chipafarm.com')
on conflict (id) do update set role = excluded.role, is_active = true;
